GameEndState = class("GameEndState", GameState)

local function doReward(player, rank, allRankData)
    if not player then
        return
    end

    player.property:addInvincibleState(Utility.dayTime, true)

    local coin = RewardConfig:getCoinReward(rank)
    player.property:changeChampionShipCoin(coin)

    local muscle = RewardConfig:getMuscleReward(rank, player.property.advancedLevel)
    player.property:changeMuscleMass(muscle)

    local gold = RewardConfig:getGoldReward(rank, player.property.advancedLevel)
    player.property:changeGold(gold)

    local userId = player.userId
    local score = player.score
    local curKill = player.curKill
    LogUtil.log("doReward " .. tostring(userId) .. " " .. score .. " " .. curKill)
    LSChampionShipWeb:UploadScore(userId, score, curKill)

    local stage = GameConfig.currentChampionshipsLv
    local data = {{},{}}
    -- 结算奖励数据
    data[1] = {
        muscle = muscle,
        gold   = gold,
        coin   = coin,
        score  = score,
        rank   = rank,
        stage  = stage,--进阶用于决定锦标赛阶段
    }
    -- 结算计分排行数据
    data[2] = allRankData
    GamePacketSender:sendShowResultAward(player.rakssid, data)
end

function GameEndState:enter()
    self.GameStatus = Define.GameStatus.GameEnd
    self.countDownTime = ChampionShipConfig.gameOverBackHallCountDownTime
    LSRankManager:updateAllPlayerRealRank()
    local meRank = {}
    local allRank = {}
    for i, Value in pairs(LSRankManager.Ranks) do
        meRank[i] = {
                ["rakssid"] = Value.rakssid,
                ["rank"] = Value.rank
            }
        allRank[i] = {
                rank = Value.rank,
                name = Value.name,
                kill = Value.kill,
                stage = Value.stage,
                score = Value.score
            }
    end
    for i=1,#meRank do
        local player = PlayerManager:getPlayerByRakssid(meRank[i].rakssid)
        if player then
            doReward(player, meRank[i].rank, allRank)
        end
    end
end

function GameEndState:update()
    self.countDownTime = self.countDownTime - 1
    if self.countDownTime > 0 then
        MsgSender.sendTopTips(1, IMessages:msgCloseServerTimeHint(self.countDownTime, IMessages.UNIT_SECOND, false))
    elseif self.countDownTime % ChampionShipConfig.gameOverBackHallCountDownTime == 0 then
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            JumpGameManager:addPlayer(player, "g1055")
        end
        LogUtil.log("GameEndState:update() : gameOverBackHallCountDownTime self.countDownTime : "..tostring(self.countDownTime))
    end
end

function GameEndState:leave()
    --TODO
end

